use chrono::{DateTime, Utc};
use uuid::Uuid;

use super::context::ContextId;
use super::project::ProjectId;
use super::todo_title::TodoTitle;
use super::user::UserId;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct NextActionId(Uuid);

impl Default for NextActionId {
    fn default() -> Self {
        Self::new()
    }
}

impl NextActionId {
    pub fn new() -> Self {
        Self(Uuid::new_v4())
    }

    pub fn from_uuid(uuid: Uuid) -> Self {
        Self(uuid)
    }

    pub fn as_uuid(&self) -> &Uuid {
        &self.0
    }
}

/// A concrete, physical action ready to do. Has a context (required) and
/// an optional project link (projects come in Step 6, so project_id is
/// nullable for now).
///
/// State machine:
///   Active --complete()--> Completed
///
/// Completed actions are removed from the active Next Actions list.
#[derive(Debug, Clone)]
pub enum NextAction {
    Active {
        id: NextActionId,
        user_id: UserId,
        context_id: ContextId,
        project_id: Option<ProjectId>,
        title: TodoTitle,
        created_at: DateTime<Utc>,
    },
    Completed {
        id: NextActionId,
        user_id: UserId,
        context_id: ContextId,
        project_id: Option<ProjectId>,
        title: TodoTitle,
        created_at: DateTime<Utc>,
        completed_at: DateTime<Utc>,
    },
}

impl NextAction {
    pub fn new(user_id: UserId, context_id: ContextId, title: TodoTitle) -> Self {
        Self::Active {
            id: NextActionId::new(),
            user_id,
            context_id,
            project_id: None,
            title,
            created_at: Utc::now(),
        }
    }

    pub fn new_for_project(
        user_id: UserId,
        context_id: ContextId,
        project_id: ProjectId,
        title: TodoTitle,
    ) -> Self {
        Self::Active {
            id: NextActionId::new(),
            user_id,
            context_id,
            project_id: Some(project_id),
            title,
            created_at: Utc::now(),
        }
    }

    pub fn from_parts(
        id: NextActionId,
        user_id: UserId,
        context_id: ContextId,
        project_id: Option<ProjectId>,
        title: TodoTitle,
        created_at: DateTime<Utc>,
        completed_at: Option<DateTime<Utc>>,
    ) -> Self {
        match completed_at {
            Some(completed_at) => Self::Completed {
                id,
                user_id,
                context_id,
                project_id,
                title,
                created_at,
                completed_at,
            },
            None => Self::Active {
                id,
                user_id,
                context_id,
                project_id,
                title,
                created_at,
            },
        }
    }

    pub fn id(&self) -> &NextActionId {
        match self {
            Self::Active { id, .. } | Self::Completed { id, .. } => id,
        }
    }

    pub fn user_id(&self) -> &UserId {
        match self {
            Self::Active { user_id, .. } | Self::Completed { user_id, .. } => user_id,
        }
    }

    pub fn context_id(&self) -> &ContextId {
        match self {
            Self::Active { context_id, .. } | Self::Completed { context_id, .. } => context_id,
        }
    }

    pub fn project_id(&self) -> Option<&ProjectId> {
        match self {
            Self::Active { project_id, .. } | Self::Completed { project_id, .. } => {
                project_id.as_ref()
            }
        }
    }

    pub fn title(&self) -> &TodoTitle {
        match self {
            Self::Active { title, .. } | Self::Completed { title, .. } => title,
        }
    }

    pub fn created_at(&self) -> &DateTime<Utc> {
        match self {
            Self::Active { created_at, .. } | Self::Completed { created_at, .. } => created_at,
        }
    }

    pub fn is_active(&self) -> bool {
        matches!(self, Self::Active { .. })
    }

    pub fn is_completed(&self) -> bool {
        matches!(self, Self::Completed { .. })
    }

    /// Transitions an Active next action to Completed.
    /// If already completed, returns self unchanged.
    pub fn complete(self) -> Self {
        match self {
            Self::Active {
                id,
                user_id,
                context_id,
                project_id,
                title,
                created_at,
            } => Self::Completed {
                id,
                user_id,
                context_id,
                project_id,
                title,
                created_at,
                completed_at: Utc::now(),
            },
            completed @ Self::Completed { .. } => completed,
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn next_action_id_is_unique() {
        let id1 = NextActionId::new();
        let id2 = NextActionId::new();
        assert_ne!(id1, id2);
    }

    #[test]
    fn next_action_id_from_uuid_roundtrips() {
        let uuid = Uuid::new_v4();
        let id = NextActionId::from_uuid(uuid);
        assert_eq!(id.as_uuid(), &uuid);
    }

    #[test]
    fn new_next_action_is_active() {
        let user_id = UserId::new();
        let context_id = ContextId::new();
        let title = TodoTitle::parse("Buy groceries".to_string()).unwrap();
        let action = NextAction::new(user_id, context_id, title);

        assert!(action.is_active());
        assert!(!action.is_completed());
        assert_eq!(action.title().as_str(), "Buy groceries");
    }

    #[test]
    fn new_next_action_has_user_and_context() {
        let user_id = UserId::new();
        let context_id = ContextId::new();
        let title = TodoTitle::parse("Call dentist".to_string()).unwrap();
        let action = NextAction::new(user_id.clone(), context_id.clone(), title);

        assert_eq!(action.user_id(), &user_id);
        assert_eq!(action.context_id(), &context_id);
    }

    #[test]
    fn complete_transitions_active_to_completed() {
        let action = NextAction::new(
            UserId::new(),
            ContextId::new(),
            TodoTitle::parse("File taxes".to_string()).unwrap(),
        );

        let completed = action.complete();
        assert!(completed.is_completed());
        assert!(!completed.is_active());
    }

    #[test]
    fn complete_preserves_id_and_fields() {
        let user_id = UserId::new();
        let context_id = ContextId::new();
        let title = TodoTitle::parse("Send email".to_string()).unwrap();
        let action = NextAction::new(user_id.clone(), context_id.clone(), title);
        let id = action.id().clone();

        let completed = action.complete();
        assert_eq!(completed.id(), &id);
        assert_eq!(completed.user_id(), &user_id);
        assert_eq!(completed.context_id(), &context_id);
        assert_eq!(completed.title().as_str(), "Send email");
    }

    #[test]
    fn complete_is_noop_on_completed_action() {
        let action = NextAction::new(
            UserId::new(),
            ContextId::new(),
            TodoTitle::parse("Already done".to_string()).unwrap(),
        );
        let completed = action.complete();
        assert!(completed.is_completed());

        // Completing again should not change anything
        let still_completed = completed.complete();
        assert!(still_completed.is_completed());
    }

    #[test]
    fn from_parts_creates_active_when_no_completed_at() {
        let id = NextActionId::new();
        let user_id = UserId::new();
        let context_id = ContextId::new();
        let title = TodoTitle::parse("Test".to_string()).unwrap();
        let now = Utc::now();

        let action = NextAction::from_parts(
            id.clone(),
            user_id.clone(),
            context_id.clone(),
            None,
            title,
            now,
            None,
        );

        assert!(action.is_active());
        assert_eq!(action.id(), &id);
        assert_eq!(action.user_id(), &user_id);
        assert_eq!(action.context_id(), &context_id);
        assert_eq!(action.created_at(), &now);
    }

    #[test]
    fn from_parts_creates_completed_when_completed_at_present() {
        let id = NextActionId::new();
        let user_id = UserId::new();
        let context_id = ContextId::new();
        let title = TodoTitle::parse("Done task".to_string()).unwrap();
        let created = Utc::now();
        let completed = Utc::now();

        let action = NextAction::from_parts(
            id.clone(),
            user_id.clone(),
            context_id.clone(),
            None,
            title,
            created,
            Some(completed),
        );

        assert!(action.is_completed());
        assert_eq!(action.id(), &id);
    }
}

use sqlx::PgPool;

use crate::domain::{ContextId, NextAction, Project, ProjectId, TodoTitle, TodoTitleError, UserId};
use crate::infrastructure::{next_action_repository, project_repository};

#[derive(Debug, thiserror::Error)]
pub enum AddProjectError {
    #[error("Invalid title: {0}")]
    InvalidTitle(#[from] TodoTitleError),
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

#[tracing::instrument(
    name = "add_project",
    skip(pool, title),
    fields(user_id = %user_id.as_uuid())
)]
pub async fn add_project(
    pool: &PgPool,
    user_id: UserId,
    title: String,
) -> Result<Project, AddProjectError> {
    let title = TodoTitle::parse(title)?;
    let project = Project::new(user_id, title);

    project_repository::insert_project(pool, &project)
        .await
        .map_err(|e| {
            AddProjectError::Unexpected(anyhow::anyhow!("Failed to insert project: {e}"))
        })?;

    tracing::info!("Project added");
    Ok(project)
}

#[tracing::instrument(
    name = "list_active_projects",
    skip(pool),
    fields(user_id = %user_id.as_uuid())
)]
pub async fn list_active_projects(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<Vec<Project>, anyhow::Error> {
    let projects = project_repository::find_active_projects_by_user(pool, user_id)
        .await
        .map_err(|e| anyhow::anyhow!("Failed to fetch projects: {e}"))?;

    Ok(projects)
}

#[tracing::instrument(
    name = "count_active_projects",
    skip(pool),
    fields(user_id = %user_id.as_uuid())
)]
pub async fn count_active_projects(pool: &PgPool, user_id: &UserId) -> Result<i64, anyhow::Error> {
    let count = project_repository::count_active_projects(pool, user_id)
        .await
        .map_err(|e| anyhow::anyhow!("Failed to count projects: {e}"))?;

    Ok(count)
}

#[tracing::instrument(
    name = "count_stalled_projects",
    skip(pool),
    fields(user_id = %user_id.as_uuid())
)]
pub async fn count_stalled_projects(pool: &PgPool, user_id: &UserId) -> Result<i64, anyhow::Error> {
    let count = project_repository::count_stalled_projects(pool, user_id)
        .await
        .map_err(|e| anyhow::anyhow!("Failed to count stalled projects: {e}"))?;

    Ok(count)
}

#[derive(Debug, thiserror::Error)]
pub enum CompleteProjectError {
    #[error("Project not found")]
    NotFound,
    #[error("Not authorized to complete this project")]
    Unauthorized,
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

#[tracing::instrument(
    name = "complete_project",
    skip(pool),
    fields(project_id = %project_id.as_uuid(), user_id = %user_id.as_uuid())
)]
pub async fn complete_project(
    pool: &PgPool,
    project_id: &ProjectId,
    user_id: &UserId,
) -> Result<(), CompleteProjectError> {
    let project = project_repository::find_project_by_id(pool, project_id)
        .await
        .map_err(|e| CompleteProjectError::Unexpected(anyhow::anyhow!("Database error: {e}")))?
        .ok_or(CompleteProjectError::NotFound)?;

    if project.user_id() != user_id {
        return Err(CompleteProjectError::Unauthorized);
    }

    let completed = project.complete();
    if let Project::Completed { completed_at, .. } = &completed {
        project_repository::complete_project(pool, project_id, completed_at)
            .await
            .map_err(|e| {
                CompleteProjectError::Unexpected(anyhow::anyhow!("Failed to complete project: {e}"))
            })?;
    }

    tracing::info!("Project completed");
    Ok(())
}

#[derive(Debug, thiserror::Error)]
pub enum DeleteProjectError {
    #[error("Project not found")]
    NotFound,
    #[error("Not authorized to delete this project")]
    Unauthorized,
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

#[tracing::instrument(
    name = "delete_project",
    skip(pool),
    fields(project_id = %project_id.as_uuid(), user_id = %user_id.as_uuid())
)]
pub async fn delete_project(
    pool: &PgPool,
    project_id: &ProjectId,
    user_id: &UserId,
) -> Result<(), DeleteProjectError> {
    let project = project_repository::find_project_by_id(pool, project_id)
        .await
        .map_err(|e| DeleteProjectError::Unexpected(anyhow::anyhow!("Database error: {e}")))?
        .ok_or(DeleteProjectError::NotFound)?;

    if project.user_id() != user_id {
        return Err(DeleteProjectError::Unauthorized);
    }

    project_repository::delete_project(pool, project_id)
        .await
        .map_err(|e| {
            DeleteProjectError::Unexpected(anyhow::anyhow!("Failed to delete project: {e}"))
        })?;

    tracing::info!("Project deleted");
    Ok(())
}

#[derive(Debug, thiserror::Error)]
pub enum UpdateProjectTitleError {
    #[error("Project not found")]
    NotFound,
    #[error("Not authorized to edit this project")]
    Unauthorized,
    #[error("Invalid title: {0}")]
    InvalidTitle(#[from] TodoTitleError),
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

#[tracing::instrument(
    name = "update_project_title",
    skip(pool, new_title),
    fields(project_id = %project_id.as_uuid(), user_id = %user_id.as_uuid())
)]
pub async fn update_project_title(
    pool: &PgPool,
    project_id: &ProjectId,
    user_id: &UserId,
    new_title: String,
) -> Result<(), UpdateProjectTitleError> {
    let project = project_repository::find_project_by_id(pool, project_id)
        .await
        .map_err(|e| UpdateProjectTitleError::Unexpected(anyhow::anyhow!("Database error: {e}")))?
        .ok_or(UpdateProjectTitleError::NotFound)?;

    if project.user_id() != user_id {
        return Err(UpdateProjectTitleError::Unauthorized);
    }

    let title = TodoTitle::parse(new_title)?;

    // We need an update_project_title repo function
    sqlx::query!(
        r#"UPDATE projects SET title = $1 WHERE id = $2"#,
        title.as_str(),
        project_id.as_uuid(),
    )
    .execute(pool)
    .await
    .map_err(|e| {
        UpdateProjectTitleError::Unexpected(anyhow::anyhow!("Failed to update project title: {e}"))
    })?;

    tracing::info!("Project title updated");
    Ok(())
}

#[derive(Debug, thiserror::Error)]
pub enum GetProjectError {
    #[error("Project not found")]
    NotFound,
    #[error("Not authorized to view this project")]
    Unauthorized,
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

pub struct ProjectDetail {
    pub project: Project,
    pub next_actions: Vec<NextAction>,
    pub active_next_action_count: i64,
}

#[tracing::instrument(
    name = "get_project_detail",
    skip(pool),
    fields(project_id = %project_id.as_uuid(), user_id = %user_id.as_uuid())
)]
pub async fn get_project_detail(
    pool: &PgPool,
    project_id: &ProjectId,
    user_id: &UserId,
) -> Result<ProjectDetail, GetProjectError> {
    let project = project_repository::find_project_by_id(pool, project_id)
        .await
        .map_err(|e| GetProjectError::Unexpected(anyhow::anyhow!("Database error: {e}")))?
        .ok_or(GetProjectError::NotFound)?;

    if project.user_id() != user_id {
        return Err(GetProjectError::Unauthorized);
    }

    let next_actions = next_action_repository::find_next_actions_by_project(pool, project_id)
        .await
        .map_err(|e| {
            GetProjectError::Unexpected(anyhow::anyhow!("Failed to fetch next actions: {e}"))
        })?;

    let active_next_action_count = project_repository::count_project_next_actions(pool, project_id)
        .await
        .map_err(|e| {
            GetProjectError::Unexpected(anyhow::anyhow!("Failed to count next actions: {e}"))
        })?;

    Ok(ProjectDetail {
        project,
        next_actions,
        active_next_action_count,
    })
}

#[derive(Debug, thiserror::Error)]
pub enum AddProjectNextActionError {
    #[error("Project not found")]
    ProjectNotFound,
    #[error("Not authorized")]
    Unauthorized,
    #[error("Invalid title: {0}")]
    InvalidTitle(#[from] TodoTitleError),
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

#[tracing::instrument(
    name = "add_next_action_to_project",
    skip(pool, title),
    fields(project_id = %project_id.as_uuid(), user_id = %user_id.as_uuid(), context_id = %context_id.as_uuid())
)]
pub async fn add_next_action_to_project(
    pool: &PgPool,
    user_id: &UserId,
    project_id: &ProjectId,
    context_id: ContextId,
    title: String,
) -> Result<NextAction, AddProjectNextActionError> {
    let project = project_repository::find_project_by_id(pool, project_id)
        .await
        .map_err(|e| AddProjectNextActionError::Unexpected(anyhow::anyhow!("Database error: {e}")))?
        .ok_or(AddProjectNextActionError::ProjectNotFound)?;

    if project.user_id() != user_id {
        return Err(AddProjectNextActionError::Unauthorized);
    }

    let title = TodoTitle::parse(title)?;
    let action =
        NextAction::new_for_project(user_id.clone(), context_id, project_id.clone(), title);

    next_action_repository::insert_next_action(pool, &action)
        .await
        .map_err(|e| {
            AddProjectNextActionError::Unexpected(anyhow::anyhow!(
                "Failed to insert next action: {e}"
            ))
        })?;

    tracing::info!("Next action added to project");
    Ok(action)
}

use chrono::{DateTime, Utc};
use sqlx::{PgExecutor, PgPool};
use uuid::Uuid;

use crate::domain::{Project, ProjectId, TodoTitle, UserId};

struct ProjectRecord {
    id: Uuid,
    user_id: Uuid,
    title: String,
    created_at: DateTime<Utc>,
    completed_at: Option<DateTime<Utc>>,
    dropped_at: Option<DateTime<Utc>>,
}

impl ProjectRecord {
    fn into_domain(self) -> Project {
        let id = ProjectId::from_uuid(self.id);
        let user_id = UserId::from_uuid(self.user_id);
        let title = TodoTitle::parse(self.title).expect("stored title should be valid");

        Project::from_parts(
            id,
            user_id,
            title,
            self.created_at,
            self.completed_at,
            self.dropped_at,
        )
    }
}

pub async fn insert_project(
    executor: impl PgExecutor<'_>,
    project: &Project,
) -> Result<(), sqlx::Error> {
    let (completed_at, dropped_at): (Option<&DateTime<Utc>>, Option<&DateTime<Utc>>) = match project
    {
        Project::Completed { completed_at, .. } => (Some(completed_at), None),
        Project::Dropped { dropped_at, .. } => (None, Some(dropped_at)),
        Project::Active { .. } => (None, None),
    };

    sqlx::query!(
        r#"INSERT INTO projects (id, user_id, title, created_at, completed_at, dropped_at)
           VALUES ($1, $2, $3, $4 :: timestamptz, $5 :: timestamptz, $6 :: timestamptz)"#,
        project.id().as_uuid(),
        project.user_id().as_uuid(),
        project.title().as_str(),
        project.created_at() as &DateTime<Utc>,
        completed_at as Option<&DateTime<Utc>>,
        dropped_at as Option<&DateTime<Utc>>,
    )
    .execute(executor)
    .await?;
    Ok(())
}

pub async fn find_active_projects_by_user(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<Vec<Project>, sqlx::Error> {
    let records = sqlx::query_as!(
        ProjectRecord,
        r#"SELECT id, user_id, title,
           created_at as "created_at: DateTime<Utc>",
           completed_at as "completed_at: DateTime<Utc>",
           dropped_at as "dropped_at: DateTime<Utc>"
           FROM projects
           WHERE user_id = $1 AND completed_at IS NULL AND dropped_at IS NULL
           ORDER BY created_at ASC"#,
        user_id.as_uuid(),
    )
    .fetch_all(pool)
    .await?;

    Ok(records.into_iter().map(|r| r.into_domain()).collect())
}

pub async fn find_project_by_id(
    executor: impl PgExecutor<'_>,
    project_id: &ProjectId,
) -> Result<Option<Project>, sqlx::Error> {
    let record: Option<ProjectRecord> = sqlx::query_as!(
        ProjectRecord,
        r#"SELECT id, user_id, title,
           created_at as "created_at: DateTime<Utc>",
           completed_at as "completed_at: DateTime<Utc>",
           dropped_at as "dropped_at: DateTime<Utc>"
           FROM projects WHERE id = $1"#,
        project_id.as_uuid(),
    )
    .fetch_optional(executor)
    .await?;

    Ok(record.map(|r| r.into_domain()))
}

pub async fn complete_project(
    pool: &PgPool,
    project_id: &ProjectId,
    completed_at: &DateTime<Utc>,
) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"UPDATE projects SET completed_at = $1 :: timestamptz WHERE id = $2"#,
        completed_at as &DateTime<Utc>,
        project_id.as_uuid(),
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn delete_project(pool: &PgPool, project_id: &ProjectId) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"DELETE FROM projects WHERE id = $1"#,
        project_id.as_uuid(),
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn count_active_projects(pool: &PgPool, user_id: &UserId) -> Result<i64, sqlx::Error> {
    let record = sqlx::query!(
        r#"SELECT COUNT(*) as "count!" FROM projects WHERE user_id = $1 AND completed_at IS NULL AND dropped_at IS NULL"#,
        user_id.as_uuid(),
    )
    .fetch_one(pool)
    .await?;

    Ok(record.count)
}

/// Count stalled projects (active projects with no active next actions)
pub async fn count_stalled_projects(pool: &PgPool, user_id: &UserId) -> Result<i64, sqlx::Error> {
    let record = sqlx::query!(
        r#"SELECT COUNT(*) as "count!"
           FROM projects p
           WHERE p.user_id = $1
             AND p.completed_at IS NULL
             AND p.dropped_at IS NULL
             AND NOT EXISTS (
                 SELECT 1 FROM next_actions na
                 WHERE na.project_id = p.id
                   AND na.completed_at IS NULL
             )"#,
        user_id.as_uuid(),
    )
    .fetch_one(pool)
    .await?;

    Ok(record.count)
}

/// Count active next actions for a specific project
pub async fn count_project_next_actions(
    pool: &PgPool,
    project_id: &ProjectId,
) -> Result<i64, sqlx::Error> {
    let record = sqlx::query!(
        r#"SELECT COUNT(*) as "count!" FROM next_actions WHERE project_id = $1 AND completed_at IS NULL"#,
        project_id.as_uuid(),
    )
    .fetch_one(pool)
    .await?;

    Ok(record.count)
}

