138→pub async fn post_project(
139→    AuthenticatedUser(user_id): AuthenticatedUser,
140→    State(pool): State<PgPool>,
141→    headers: HeaderMap,
142→    Form(form): Form<AddProjectForm>,
143→) -> Result<Response, ProjectError> {
144→    let htmx = is_htmx_request(&headers);
145→
146→    if form.title.trim().is_empty() {
147→        if htmx {
148→            return Ok(StatusCode::NO_CONTENT.into_response());
149→        }
150→        return Ok(Redirect::to("/projects").into_response());
151→    }
152→
153→    match project_service::add_project(&pool, user_id.clone(), form.title).await {
154→        Ok(project) => {
155→            if htmx {
156→                let template = ProjectItemTemplate {
157→                    project: build_project_view(&project, 0),
158→                };
159→                let body = template.render().map_err(ProjectError::Render)?;
160→                Ok(htmx_response_with_announce(Html(body), "Project added"))
161→            } else {
162→                Ok(Redirect::to("/projects").into_response())
163→            }
164→        }
165→        Err(AddProjectError::InvalidTitle(title_err)) => {
166→            let user_facing = match title_err {
167→                TodoTitleError::Empty => {
168→                    if htmx {
169→                        return Ok(StatusCode::NO_CONTENT.into_response());
170→                    }
171→                    return Ok(Redirect::to("/projects").into_response());
172→                }
173→                TodoTitleError::TooLong { max, .. } => {
174→                    format!("That title is too long (max {max} characters)")
175→                }
176→            };
177→
178→            render_projects_with_error(&pool, &user_id, &user_facing).await
179→        }
180→        Err(AddProjectError::Unexpected(err)) => Err(ProjectError::Unexpected(err)),
181→    }
182→}
